import UIKit
import Alamofire

// Basic structures to handle stocks and portfolio
struct Stock {
    let symbol: String
    let price: Double
}

struct Portfolio {
    var stocks: [Stock]
}

// Basic API handler
class APIHandler {
    private let baseURL = "Your API URL"

    func getStockPrice(symbol: String, completion: @escaping (Double) -> Void) {
        let url = baseURL + "/stockPrice?symbol=\(symbol)"
        Alamofire.request(url).responseJSON { response in
            if let json = response.result.value as? [String: Any],
               let price = json["price"] as? Double {
                completion(price)
            }
        }
    }
}

// Basic stock trading functionality
class StockTrader {
    var portfolio: Portfolio

    init(portfolio: Portfolio) {
        self.portfolio = portfolio
    }

    func buyStock(stock: Stock) {
        portfolio.stocks.append(stock)
    }

    func sellStock(symbol: String) {
        portfolio.stocks.removeAll { $0.symbol == symbol }
    }
}

// Example of how to use the classes
let apiHandler = APIHandler()

apiHandler.getStockPrice(symbol: "AAPL") { price in
    let stock = Stock(symbol: "AAPL", price: price)
    let trader = StockTrader(portfolio: Portfolio(stocks: []))

    trader.buyStock(stock: stock)
    trader.sellStock(symbol: "AAPL")
}